lessons.example:
Disqus Kurulum Adımları:

1. disqus.com → Get Started → I want to install Disqus
2. Site adını gir ve shortname oluştur (codeia-blog)
3. Platform seç (Universal Code)
4. Kodu sayfana ekle:

<div id="disqus_thread"></div>
<script>
  var disqus_config = function () {
    // Sayfa URL'si
    this.page.url = 'https://sitem.com/makale-1';
    // Benzersiz sayfa ID
    this.page.identifier = 'makale-1';
  };

  (function() {
    var d = document, s = d.createElement('script');
    s.src = 'https://codeia-blog.disqus.com/embed.js';
    s.setAttribute('data-timestamp', +new Date());
    (d.head || d.body).appendChild(s);
  })();
</script>
